  run: |
    echo "=== Color Palette Validation ==="

    echo "Step 1: Checking for zinc-* colors..."
    ZINC_COUNT=\$(grep -r 'zinc-' apps/web/src --include='*.tsx' | wc -l)
    if [ "\$ZINC_COUNT" -gt 0 ]; then
      echo "[FAIL] Found \$ZINC_COUNT zinc-* occurrences"
      grep -rn 'zinc-' apps/web/src --include='*.tsx' | head -20
      exit 1
    fi
    echo "[PASS] No zinc-* colors found"

    echo "Step 2: Checking for unauthorized indigo-* colors..."
    INDIGO_FILES=\$(grep -rl 'indigo-' apps/web/src --include='*.tsx' | grep -v 'SpotlightSearch' || true)
    if [ -n "\$INDIGO_FILES" ]; then
      echo "[FAIL] Found indigo-* in non-allowlisted files:"
      echo "\$INDIGO_FILES"
      exit 1
    fi
    echo "[PASS] Indigo usage is controlled"

    echo "Step 3: Checking for arbitrary text sizes..."
    ARB_COUNT=\$(grep -rE 'text-\[[0-9]+px\]' apps/web/src --include='*.tsx' | wc -l)
    if [ "\$ARB_COUNT" -gt 0 ]; then
      echo "[FAIL] Found \$ARB_COUNT arbitrary text sizes"
      grep -rnE 'text-\[[0-9]+px\]' apps/web/src --include='*.tsx'
      exit 1
    fi
    echo "[PASS] No arbitrary text sizes found"

    echo "=== All color checks passed ==="
```

## Logging Details
Every test logs with consistent format:
